CREATE TABLE products (
  product_id INT PRIMARY KEY,
  name       VARCHAR(80),
  category   VARCHAR(40),
  price      DECIMAL(8,2),
  active     BOOLEAN DEFAULT TRUE
);

INSERT INTO products VALUES
  (1,'Laptop',   'Electronics',999.99,TRUE),
  (2,'Mouse',    'Electronics', 19.99,TRUE),
  (3,'Desk',     'Furniture',  250.00,TRUE),
  (4,'Old Model','Electronics', 79.99,FALSE);

-- View: only active products
CREATE VIEW active_products AS
  SELECT product_id, name, category, price
  FROM products
  WHERE active = TRUE;

-- Query through the view
SELECT * FROM active_products ORDER BY category, name;

-- UPDATE through the view — modifies the underlying products table
UPDATE active_products SET price = 1099.99 WHERE product_id = 1;

-- Verify in both view and base table
SELECT * FROM active_products WHERE product_id = 1;
SELECT * FROM products WHERE product_id = 1;

-- INSERT through the view (active=TRUE assumed, but view doesn't include it)
-- This INSERT will succeed and set active=TRUE by default
INSERT INTO active_products (product_id, name, category, price)
VALUES (5, 'Keyboard', 'Electronics', 59.99);

SELECT * FROM products ORDER BY product_id;

CREATE TABLE orders (
  order_id   INT PRIMARY KEY,
  customer   VARCHAR(50),
  product    VARCHAR(60),
  amount     DECIMAL(8,2),
  order_date DATE
);

INSERT INTO orders VALUES
  (1, 'Alice', 'Laptop',  999.99, '2026-01-05'),
  (2, 'Bob',   'Mouse',    19.99, '2026-01-06'),
  (3, 'Alice', 'Keyboard', 59.99, '2026-01-07'),
  (4, 'Carol', 'Monitor', 299.99, '2026-01-08'),
  (5, 'Bob',   'Laptop',  999.99, '2026-01-09');

-- Create a materialised view for customer totals
CREATE MATERIALIZED VIEW customer_totals AS
  SELECT customer, COUNT(*) AS orders, SUM(amount) AS total_spent
  FROM orders
  GROUP BY customer
  ORDER BY total_spent DESC;

-- Query the materialised view (reads from stored data, not live)
SELECT * FROM customer_totals;

-- Add new order
INSERT INTO orders VALUES (6, 'Carol', 'Headphones', 79.99, '2026-01-10');

-- Before refresh: Carol's total is stale
SELECT * FROM customer_totals WHERE customer = 'Carol';

-- Refresh the materialised view
REFRESH MATERIALIZED VIEW customer_totals;

-- After refresh: Carol's total is up-to-date
SELECT * FROM customer_totals;
